import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { callsGraphRule } from "./calls-graph.rule.js";

// a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_calls_graph
describe("calls-graph rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, callsGraphRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_calls_graph
    it("op with @calls and @doc not mentioning callee — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Sdk })
          namespace Components.ContextSdk {
            @operation(#{})
            op fetch_context(pr_url: string): string;
          }

          @component(#{
            type: ComponentType.Agent,
          })
          @dependsOn([Components.ContextSdk])
          @testing(Components.ContextSdk, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
          namespace Components.MyAgent {
            @doc("Summarizes a pull request by analyzing its diff")
            @tool(#{ sequential: false })
            @calls([Components.ContextSdk.fetch_context])
            op summarize_pr(): void;
          }
        `)
        .toBeValid();
    });

    it("op with @reads and @doc not mentioning model — no diagnostic", async () => {
      await ruleTester
        .expect(`
          namespace Components {
            @component(#{ type: ComponentType.Store })
            namespace TaskStore {
              model TaskRow { id: string; }
            }

            @component(#{ type: ComponentType.Agent })
            @dependsOn([Components.TaskStore])
            @testing(Components.TaskStore, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
            namespace ReviewAgent {
              @doc("Retrieves the current task")
              @tool(#{ sequential: false })
              @reads([Components.TaskStore.TaskRow])
              op get_task(): void;
            }
          }
        `)
        .toBeValid();
    });

    it("op without @calls/@reads/@writes — no diagnostic even with @doc", async () => {
      await ruleTester
        .expect(`
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.MyAgent {
            @doc("Summarizes a pull request")
            @tool(#{ sequential: false })
            op summarize_pr(): void;
          }
        `)
        .toBeValid();
    });

    it("op outside @component — rule skips it", async () => {
      await ruleTester
        .expect(`
          op standalone(): void;
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // Rule fires when @doc contains a {@ref} that resolves to a declared @calls target.
    // Bare words in @doc do not fire — only {@...} typed references do.

    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_calls_graph:Products.A10nBlueprintEngine.Features.OperationCallGraph.doc_omits_facts:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_entity_field_reachable:Products.A10nBlueprintEngine.Features.OperationCallGraph.doc_omits_facts:must
    it("@calls + @doc containing {@ref} to callee op — fires calls-graph", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Sdk })
          namespace Components.ContextSdk {
            @operation(#{})
            op fetch_context(pr_url: string): string;
          }

          @component(#{
            type: ComponentType.Agent,
          })
          @dependsOn([Components.ContextSdk])
          @testing(Components.ContextSdk, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
          namespace Components.MyAgent {
            @doc("Invokes {\\@Components.ContextSdk.fetch_context} to gather context")
            @tool(#{ sequential: false })
            @calls([Components.ContextSdk.fetch_context])
            op summarize_pr(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/calls-graph",
          message: /summarize_pr/,
        });
    });

    it("@reads + @doc containing {@ref} to store model — fires calls-graph", async () => {
      await ruleTester
        .expect(`
          namespace Components {
            @component(#{ type: ComponentType.Store })
            namespace TaskStore {
              model TaskRow { id: string; }
            }

            @component(#{ type: ComponentType.Agent })
            @dependsOn([Components.TaskStore])
            @testing(Components.TaskStore, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
            namespace ReviewAgent {
              @doc("Reads a {\\@Components.TaskStore.TaskRow} from the store")
              @tool(#{ sequential: false })
              @reads([Components.TaskStore.TaskRow])
              op get_task(): void;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/calls-graph",
          message: /get_task/,
        });
    });

    it("@writes + @doc containing {@ref} to store model — fires calls-graph", async () => {
      await ruleTester
        .expect(`
          namespace Components {
            @component(#{ type: ComponentType.Store })
            namespace TaskStore {
              model TaskRow { id: string; }
            }

            @component(#{ type: ComponentType.Agent })
            @dependsOn([Components.TaskStore])
            @testing(Components.TaskStore, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
            namespace ReviewAgent {
              @doc("Persists a new {\\@Components.TaskStore.TaskRow}")
              @tool(#{ sequential: false })
              @writes([Components.TaskStore.TaskRow])
              op create_task(): void;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/calls-graph",
          message: /create_task/,
        });
    });

    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_calls_graph:Products.A10nBlueprintEngine.Features.OperationCallGraph.runtime_within_deps:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_entity_field_reachable:Products.A10nBlueprintEngine.Features.OperationCallGraph.runtime_within_deps:must
    // Cross-component @calls edge whose target's component has NO @testing declaration on
    // the source component — rule fires missingTesting. This proves the runtime_within_deps
    // invariant is enforced by the typed call graph: every cross-component edge requires an
    // accompanying @testing declaration naming the dep, so a test author can read the
    // testing approach from the source component's spec alone.
    it("@calls cross-component without @testing on source component — fires missingTesting", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Sdk })
          namespace Components.ContextSdk {
            @operation(#{})
            op fetch_context(pr_url: string): string;
          }

          @component(#{ type: ComponentType.Agent })
          @dependsOn([Components.ContextSdk])
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            @calls([Components.ContextSdk.fetch_context])
            op summarize_pr(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/calls-graph",
          message: /no @testing declaration|@testing\(Components\.ContextSdk/,
        });
    });
  });
});
